// Suppress Next.js auto-generated route validator type errors.
// The validator in .next/types/validator.ts imports LayoutRoutes from ./routes.js
// which is also auto-generated and may not be available at type-check time.
// These declarations are forward-declared to satisfy the validator's imports.
declare module '../.next/types/routes.js' {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  export type LayoutRoutes = unknown;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  export type AppRouteHandlerRoutes = unknown;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  export type AppRoutes = unknown;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  export type Route = unknown;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  export type ParamMap = unknown;
}
